import openai
import json

client = openai.OpenAI()

def detect_schema_drift(thread_id, expected_schema):
    run = client.beta.threads.runs.create(
        thread_id=thread_id,
        assistant_id='asst_123',
    )
    run = client.beta.threads.runs.wait(thread_id, run.id)

    messages = client.beta.threads.messages.list(thread_id)
    for msg in messages.data:
        if msg.role == 'assistant' and msg.tool_calls:
            for tool_call in msg.tool_calls:
                args = json.loads(tool_call.function.arguments)
                # Validate against expected_schema using jsonschema
                try:
                    jsonschema.validate(instance=args, schema=expected_schema)
                except jsonschema.ValidationError as e:
                    print(f"Schema drift detected: {e.message}")
                    return False
    return True

